mapper.update:
update student_followup_record
set status = 'CANCELED',
    remark = #{remark},
    updated_at = #{updatedAt}
where id = #{id}
  and status = 'NEED_FOLLOWUP'

mapper.select:
select from student_followup_record where student_id in
#{studentId}
order by student_id asc, due_date desc, id desc

select 
from student_followup_record


        and student_tag = #{studentTag}


        and status = #{status}


        and followup_user_id = #{followupUserId}


        and due_date >= #{startDate}


        and due_date <= #{endDate}


        and exists (
            select 1 from student s
            where s.id = student_followup_record.student_id
              and s.student_name like concat('%', #{studentName}, '%')
        )


        and exists (
            select 1 from student s
            where s.id = student_followup_record.student_id
              and s.student_phone like concat('%', #{studentPhone}, '%')
        )


order by due_date asc, id desc
